UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","In order to enhance the rigor of their research proposal, students will also need to complete a semester of Research Methodology in addition to participating in periodic research seminars and workshops.","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA VOCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","Areas of Research","Sociology","Media Studies","Cinema and Television studies","Digital Entertainment","Communications","Creative Industries","Digital Ethnography","Digital Art and Design","Visual and Spatial Communication","Screen Production","Creative Writing"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'c48c85c4-bb8b-44e2-bcef-04df1fd90636';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","In order to enhance the rigor of their research proposal, students will also need to complete a semester of Research Methods in addition to participating in periodic research seminars and workshops.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA VOCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","Areas of Research","Renewable and Sustainable Energy","Advanced Materials","Photonics and Optical Devices","Wireless Communication","Internet of Things (IoT) and Artificial Intelligence","Robotic Kinematics and Motion Control","Electrical Circuits, Systems, and Power Electronics","Quality and Operational Management","Manufacturing and System Engineering"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'ac3c0330-d57f-4036-8b2f-926a3f065f26';
