UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","– Research Methods– Qualitative Methods– Quantitative Methods","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA VOCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","Areas of Research","Sociology","Cultural Studies","Political Science","Civics","Economics"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '51e85292-3209-4926-b933-5f977bff2fce';
