UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","RESEARCH","Upon the approval of the research proposal, students will be guided by their supervisors to begin their research, and will work independently on their research projects.","DISSERTATION","Upon the completion of their research, students will document the research project and process in a dissertation. Typically, dissertations for a Master by research is not more than 60,000 words.","VIVA VOLCE","Upon the completion of the research and dissertation, students will undergo an oral examination, chaired by experts in the field.","Areas of Research","Artificial Intelligence","Big Data","Machine Learning/Deep Learning","Data Visualization","Image Processing","Industry 4.0"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'd8b70774-8f0d-4f85-858a-4a48514b740c';
